var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아르티...... 내가 제대로 할 수 있을까?","JPN":"アルティ……あたしにできるかな?","ENG":"Arti... Do you think I can play too?","TWN":"阿爾蒂……我能做好嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"난 운동회 같은 건...... 자신 없는데......","JPN":"あたしは運動会みたいなのは……自信がないの……","ENG":"I've never thought about playing in the Field Day...","TWN":"我對運動會……沒有信心……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"벌써부터 약한 소릴 하면 어떡해?","JPN":"始まる前から弱音を吐いてどうするんだ？","ENG":"Come on, you should be more confident!","TWN":"怎麼能從現在就說喪氣話呢？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"우린 우승을 목표로 하고 있다고.","JPN":"ぼくたちは優勝を目指すんだよ。","ENG":"Our goal is to become the final winner.","TWN":"我們的目標是冠軍。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그러려면 믿을 수 있는 아군이 많이 필요하잖아?","JPN":"そのためには信頼できる味方が必要だから！","ENG":"And to do that, we need allies we can trust.","TWN":"要想取得冠軍，需要很多可靠的隊友不是嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"하지만...... 난 꽃 이름 외우는 것밖에 할 줄 모르는데......","JPN":"でも……あたしは花の名前を覚えることしかできないのに……","ENG":"But... The only thing I'm good at is memorizing flower names...","TWN":"可是……我只會背花兒的名字……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"내가 도움이 될 리가 없어......","JPN":"あたしが役に立つはずがない……","ENG":"I'd be useless in the field...","TWN":"不可能幫得上忙的……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"......넌 정말 너 자신에 대해서 아무것도 모르는구나.","JPN":"……君は本当に自分のことを何も知らないんだね。","ENG":"You really don't know anything about yourself.","TWN":"……你真的是一點兒都不瞭解自己啊。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"네가 특별하지 않았다면 널 내 동아리에 끌어들이지도 않았어.","JPN":"君が特別じゃなかったら、君をぼくのサークルに誘うことはしなかったよ。","ENG":"If I didn't believe you're special, I wouldn't have accepted you in my club.","TWN":"你要是不特別，我就不會讓你加入我的社團了。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"응? 그게 무슨 말이야?","JPN":"うん？　それはどういう意味なの？","ENG":"Huh? What do you mean I'm special?","TWN":"嗯？你那話是什麼意思？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"아~ 아니, 아무것도 아니야.","JPN":"あ、いや、何でもない。","ENG":"Ah. Nothing.","TWN":"沒~沒有，沒什麼。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"아무튼 넌 할 수 있어! 더듬이를 위해서 열심히 해 보자고!","JPN":"とにかく君はできる！ アホ毛ちゃんのために頑張ってみよう！","ENG":"Anyway, you can do it! Let's do it for Antenna!","TWN":"總之，你一定能做到！為了小觸角努力吧！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"스카이를 위해서......","JPN":"スカイのために……","ENG":"For Sky...","TWN":"為了絲凱……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......알겠어. 해 볼게.","JPN":"……わかった。やってみる。","ENG":"... Alright. I'll give it a try.","TWN":"……知道了，我試試看。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"너무 부담 갖지 마, 케이시!","JPN":"あまりプレッシャーと思わないで、ケイシー！","ENG":"Don't worry, Kaci!","TWN":"你別有心理負擔，卡西！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"이래 보여도 나, 운동신경이 좋거든.","JPN":"こう見えても私、運動神経はいいからね。","ENG":"I may not look strong, but I'm actually good at sports.","TWN":"別看我這樣，我的運動神經可是很發達呢。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"엄청 빨리 달릴 수도 있어! 상대가 선배들이라도 지지 않을 거야!","JPN":"とても速く走ることもできるの！　相手が先輩でも負けないんだから！","ENG":"I can run real fast! I'm sure we can win, even against senior students!","TWN":"我跑得很快！就算對手是前輩，我也不會輸的！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"응, 같이 힘내자! 스카이!","JPN":"うん、一緒に頑張ろう！　スカイ！","ENG":"Okay. Let's do our best, Sky!","TWN":"嗯，一起加油吧！絲凱！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>1경기. 꼬리 잡기.</b>","JPN":"<b>第一試合。しっぽ取りゲーム。</b>","ENG":"<b>Round 1: Catch the Tail</b>","TWN":"<b>第一場比賽：抓尾巴。</b>"},"stage":{"bg":"BLACK","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L35_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"안녕, 얘들아? 너희도 청팀이구나?","JPN":"こんにちは！　あなたたちも青組なんだね？","ENG":"Hi, girls. You guys are also on the Blue Team?","TWN":"你們好呀？你們也是藍隊的？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"네에!","JPN":"はいっ！","ENG":"Yes!","TWN":"是！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"어...... 음...... 언니는 누구세요?","JPN":"えっと……あの……お姉さんは誰ですか？","ENG":"Uh... Erm... Who are you?","TWN":"呃……嗯……姐姐你是誰呀？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아카데미 학생은 아닌 것 같은데요.","JPN":"アカデミーの生徒ではないみたいですね。","ENG":"You don't look like an Academy student.","TWN":"你好像不是學院的學生吧。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"어라? 눈썰미가 좋네?","JPN":"あら、観察力がいいんだね！","ENG":"Hmm? You have a keen eye.","TWN":"哎呦，眼光不錯哦。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"난 외부에서 아카데미 운동회에 참가하러 온 임시 편입생이야.","JPN":"私は外部からアカデミー運動会に参加しに来た臨時編入生だよ。","ENG":"I'm a temporary transfer student. I'm just here for the Field Day.","TWN":"我是從外部申請參加學院運動會的臨時插班生。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"같은 팀원으로서 경기 잘 부탁해. 이길 자신 있지?","JPN":"同じチームメンバーとしてよろしくね。試合で勝つ自信はあるよね？","ENG":"We're on the same team now, and we're going to win, right?","TWN":"既然是一個隊的，比賽時就拜託了。有信心贏吧？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"음, 이겨 볼 생각이긴 한데 대진 운이 나빠.","JPN":"うーん、勝つつもりではあるけど、対戦運が悪いんだ。","ENG":"Well, that's my plan, but we got some strong opponents.","TWN":"嗯，我們是很想贏的，可是比賽運氣不怎麼好。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"상대 팀에는 아카데미 최강이라 불리는 엘리트 중의 엘리트. 나이엘 선배가 있거든.","JPN":"相手チームにはアカデミー最強と呼ばれるエリートの中のエリート、ナイエル先輩がいるから。","ENG":"The other team has the Academy's best Counter, the elite of the elites, Naielle.","TWN":"對方隊伍中有個被稱為學院最強的精英中的精英，奈爾前輩。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"응? 저기 나이 먹고 트윈테일 하고 있는 여자애 말이야?","JPN":"え？　あそこにいる、いい年してツインテールにしている女の子のこと？","ENG":"Huh? You mean that girl with the stupid pigtail?","TWN":"嗯？是那個年紀有些大，紮著雙馬尾的女孩嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"글쎄, 그렇게 강해 보이진 않는데?","JPN":"ふうん、そんなに強そうには見えないけど？","ENG":"Hmm... She doesn't look that strong.","TWN":"嗯，看起來好像沒那麼強啊？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"성격이나 취향에 좀 문제가 있긴 하지만 실력만큼은 확실해.","JPN":"性格や好みに多少問題があるものの、実力だけは間違いないんだ。","ENG":"Her personality and fashion sense are questionable, but she really is strong.","TWN":"雖然性格和人品有點問題，但實力確實不錯。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"내가 만든 히어로 후보 리스트에서도 학생회장님 다음으로 무려 2위를 차지하고 있거든!","JPN":"ぼくが作ったヒーロー候補リストでも、生徒会長の次、なんと2位になっているから！","ENG":"Her name stands second in my Hero Candidate List, just after the Student President!","TWN":"在我製定的英雄候選人名單中排第二位，僅次於學生會長！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"흐음...... 그렇단 말이지.","JPN":"ふむ……なるほどね。","ENG":"Hmm... I see...","TWN":"呵嗯……這樣啊。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"그럼 내가 저 애를 마크할게. 아무도 공격하지 못하게 말이야.","JPN":"じゃあ、私があの子をマークするね。誰も攻撃できないように。","ENG":"Then I'll mark that girl, so that she can't attack anyone.","TWN":"那我來阻止那傢伙，讓她沒辦法攻擊別人。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"너희는 그동안 다른 선수들의 꼬리를 열심히 가져가면 돼. 할 수 있겠니?","JPN":"あなたたちはその間に他の選手のしっぽをできるだけ多く取ってきて。できるかな？","ENG":"Meanwhile, you guys go catch other players' tails. Think you can do that?","TWN":"你們只要負責搶奪其他選手的尾巴就好，能做到嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"네엡! 저한테 맡겨 주세요!","JPN":"はい！　私に任せて！","ENG":"Okay! Leave it to me!","TWN":"能！交給我吧！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"대답도 씩씩하게 잘하네. 든든한데.","JPN":"元気いっぱいの返事でいいね。心強い。","ENG":"That's the spirit. I'll be counting on you.","TWN":"回答得真響亮，不錯。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"어...... 해 보긴 하겠지만, 정말 괜찮겠어?","JPN":"えっと……やってみるけど、本当に大丈夫そう？","ENG":"Um... I guess I will try, but are you sure about this?","TWN":"呃……那我們試試，不過真的可以嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"상대는 아카데미 최강의 나이엘 블루스틸이라고.","JPN":"相手はアカデミー最強のナイエル・ブルースチールだよ。","ENG":"It's Naielle Bluesteel, the Academy's best.","TWN":"對方可是學院最強的奈爾‧布魯斯提爾。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"나도 실력이라면 조금은 자신 있거든.","JPN":"私も実力なら少しは自信があるから。","ENG":"Well, I'm pretty skilled myself.","TWN":"我對自己的實力也相當有自信。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"그러니까 서로를 믿고 최선을 다해 보는 거야.","JPN":"だからお互いを信じて最善を尽くしてみよう。","ENG":"So what we should do is to trust each other and do our best.","TWN":"所以，就讓我們相信彼此，全力以赴吧。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"알겠지?","JPN":"わかった？","ENG":"Are we clear?","TWN":"明白了嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......네! 저희도 열심히 할게요. 임시 선배님!","JPN":"……はい！　あたしたちも頑張ってみます、臨時先輩！","ENG":"Yes, we are! We'll do our best, Temporary Senior!","TWN":"……嗯！我們也會努力的！臨時前輩！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};